overlay.script:
if (window.location.href === "chrome://browser/content/browser.xhtml") {
  const { Services } = ChromeUtils.import("resource://gre/modules/Services.jsm");
  const chromeDir = Services.dirsvc.get("UChrm", Ci.nsIFile);
  const userChrome = chromeDir.clone();
  userChrome.append("userChrome.css");
  if (userChrome.exists()) {
    const uri = Services.io.newFileURI(userChrome);
    const sheet = document.createProcessingInstruction(
      "xml-stylesheet",
      `href="${uri.spec}" type="text/css"`
    );
    document.insertBefore(sheet, document.firstChild);
  }
}
